import { askClaude } from "../../../lib/claude";
import {
  buildLocalNewtonResponse,
  buildNewtonPrompt,
  getNewtonSnapshot,
} from "../../../lib/newton-mcp";

export const runtime = "nodejs";

function normalizeList(value) {
  if (!Array.isArray(value)) {
    return [];
  }

  return value
    .map((item) => {
      if (typeof item === "string") {
        return item.trim();
      }

      return String(item).trim();
    })
    .filter(Boolean);
}

export async function POST(request) {
  let body;

  try {
    body = await request.json();
  } catch {
    return Response.json({ error: "Request body must be valid JSON." }, { status: 400 });
  }

  try {
    const rawQuery = body?.query;

    if (typeof rawQuery !== "string" || !rawQuery.trim()) {
      return Response.json(
        { error: "Request body must include a non-empty string 'query'." },
        { status: 400 },
      );
    }

    const query = rawQuery.trim();
    const snapshot = await getNewtonSnapshot(query);
    const hasClaudeApiKey = Boolean(
      process.env.ANTHROPIC_API_KEY || process.env.CLAUDE_API_KEY,
    );

    if (!hasClaudeApiKey) {
      return Response.json({
        ...buildLocalNewtonResponse(query, snapshot),
        source: "newton-local",
      });
    }

    const response = await askClaude(buildNewtonPrompt(query, snapshot));
    let parsedResponse;

    try {
      parsedResponse = JSON.parse(response);
    } catch {
      throw new Error("Claude returned invalid JSON.");
    }

    if (!parsedResponse || typeof parsedResponse !== "object" || Array.isArray(parsedResponse)) {
      throw new Error("Claude returned an invalid JSON payload.");
    }

    return Response.json({
      summary:
        typeof parsedResponse.summary === "string" ? parsedResponse.summary : "",
      tasks: normalizeList(parsedResponse.tasks),
      insights: normalizeList(parsedResponse.insights),
      source: "claude-api",
    });
  } catch (error) {
    const message =
      error instanceof Error ? error.message : "Unable to process request.";

    return Response.json({ error: message }, { status: 500 });
  }
}
